// Set up the API key and base URL
const apiKey = 'YOUR_API_KEY';
const baseURL = 'https://api.openweathermap.org/data/2.5/forecast?';

// Function to fetch weather data for a city
async function fetchWeather(city) {
    try {
        const response = await fetch(`${baseURL}q=${city}&appid=${apiKey}&cnt=5&units=metric`);
        if (!response.ok) throw new Error('City not found or API error');
        const data = await response.json();
        return data;
    } catch (error) {
        console.error('Error fetching weather data:', error.message);
        return null;
    }
}

// Function to process and display the forecast
function displayForecast(data) {
    if (!data || !data.list) return;
    const forecast = data.list.map(entry => ({
        date: new Date(entry.dt * 1000).toLocaleDateString(),
        high: entry.main.temp_max,
        low: entry.main.temp_min,
        precipitation: entry.pop * 100
    }));
    console.log('5-Day Forecast:', forecast);
}

// Main function to run the application
async function runWeatherApp() {
    let city = 'London';
    while (true) {
        const weatherData = await fetchWeather(city);
        if (weatherData) {
            displayForecast(weatherData);
        } else {
            console.log('Failed to retrieve data. Retrying...');
        }
        await new Promise(resolve => setTimeout(resolve, 5 * 60 * 1000)); // 5 minutes
    }
}

// Start the application
runWeatherApp();
